class Solution {
public:
    int maxScore(string s) {
        int maxScore = 0;
        for (int i = 1; i < s.length(); i++) {
            int leftZeros = 0, rightOnes = 0;
            for (int j = 0; j < i; j++) {
                if (s[j] == '0') leftZeros++;
            }
            for (int j = i; j < s.length(); j++) {
                if (s[j] == '1') rightOnes++;
            }
            maxScore = max(maxScore, leftZeros + rightOnes);
        }
        return maxScore;
    }
};
